interface LauncherTileProps {
    id: string;
    label: string;
    icon: React.ReactNode;
    isForcedLock?: boolean;
    badgeCount?: number;
    badgeColor?: string;
    isInspectionModule?: boolean;
    isLocked: boolean;
    onNavigate: (module: string) => void;
}

const LauncherTile = ({ 
    id, label, icon, isForcedLock = false, badgeCount = 0, badgeColor = 'bg-slate-800', 
    isInspectionModule = false, isLocked, onNavigate
}: LauncherTileProps) => {
    const effectiveLock = isForcedLock || (isInspectionModule && isLocked);

    return (
        <button 
            onClick={() => !effectiveLock && onNavigate(id)}
            className={`flex flex-col items-center p-4 sm:p-6 transition-all w-full group relative rounded-2xl
                ${effectiveLock ? 'opacity-30 cursor-not-allowed grayscale' : 'hover:bg-white hover:shadow-sm active:scale-95'}`}
        >
            <div className="mb-3 flex items-center justify-center relative">
                {icon}
                {effectiveLock && (
                    <div className="absolute -top-1 -right-1 bg-slate-800 text-white rounded-full p-1 shadow-sm">
                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                    </div>
                )}
                {badgeCount > 0 && !effectiveLock && (
                    <div className={`absolute -top-1 -right-1 ${badgeColor} text-white text-[10px] font-semibold w-5 h-5 rounded-full flex items-center justify-center border border-white`}>
                        {badgeCount}
                    </div>
                )}
            </div>
            <span className={`text-xs font-medium text-center leading-tight ${effectiveLock ? 'text-slate-400' : 'text-slate-600 group-hover:text-slate-900'}`}>
                {label}
            </span>
        </button>
    );
};

