import React, { useState, useEffect, useRef } from 'react';
import { SystemSettings, User } from '../types';

interface SettingsViewProps {
    settings: SystemSettings;
    setSettings: React.Dispatch<React.SetStateAction<SystemSettings>>;
    appScriptUrl: string;
    setAppScriptUrl: (url: string) => void;
    handleSaveSettings: () => void;
    isSavingSettings: boolean;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    user?: User | null;
}

const SectionHeader = ({ label }: { label: string }) => (
    <div className="w-full flex items-center gap-6 mb-8 opacity-50">
        <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] whitespace-nowrap">{label}</span>
        <div className="h-px flex-1 bg-gradient-to-r from-slate-200 to-transparent"></div>
    </div>
);

const SettingsView: React.FC<SettingsViewProps> = ({ 
    settings, setSettings, handleSaveSettings, isSavingSettings, user, showToast
}) => {
    const [logoError, setLogoError] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => { setLogoError(false); }, [settings.companyLogo]);

    const isAdmin = user?.role === 'SuperAdmin' || user?.role === 'Admin';

    const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (file.size > 1 * 1024 * 1024) {
            showToast("Logo must be under 1MB", "error");
            return;
        }

        const reader = new FileReader();
        reader.onload = (event) => {
            const base64String = event.target?.result as string;
            setSettings(s => ({ ...s, companyLogo: base64String }));
            showToast("Logo updated", "success");
        };
        reader.readAsDataURL(file);
    };

    const inputClasses = "w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold text-slate-800 outline-none focus:ring-4 focus:ring-indigo-50/50 focus:bg-white transition-all disabled:opacity-50";
    const labelClasses = "block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1";

    return (
        <div className="max-w-4xl mx-auto py-8 sm:py-12 space-y-12 animate-fadeIn px-2">
             <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6">
                <div>
                    <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">System Settings</h2>
                    <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.3em] mt-2">Environment Configuration</p>
                </div>
                {!isAdmin && (
                    <div className="px-4 py-2 bg-amber-50 border border-amber-200 rounded-xl">
                        <span className="text-[10px] font-black text-amber-600 uppercase tracking-widest">READ-ONLY ACCESS</span>
                    </div>
                )}
             </div>

             <div className="bg-white p-8 sm:p-12 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-12">
                <section>
                    <SectionHeader label="ORGANIZATION IDENTITY" />
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="space-y-2">
                            <label className={labelClasses}>Company Legal Name</label>
                            <input type="text" disabled={!isAdmin} value={settings.companyName} onChange={(e) => setSettings(s => ({...s, companyName: e.target.value}))} className={inputClasses} placeholder="Enter company name" />
                        </div>
                        <div className="space-y-2">
                            <label className={labelClasses}>Administrative Contact</label>
                            <input type="email" disabled={!isAdmin} value={settings.managerEmail} onChange={(e) => setSettings(s => ({...s, managerEmail: e.target.value}))} className={inputClasses} placeholder="admin@company.com" />
                        </div>
                    </div>
                </section>

                <section>
                    <SectionHeader label="DISTRIBUTION LINKS" />
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="space-y-2">
                            <label className={labelClasses}>Cloud Portal Endpoint</label>
                            <input type="url" disabled={!isAdmin} value={settings.webAppUrl || ''} onChange={(e) => setSettings(s => ({...s, webAppUrl: e.target.value}))} placeholder="https://app.fleetpro.com" className={inputClasses} />
                        </div>
                        <div className="space-y-2">
                            <label className={labelClasses}>Mobile Binary (APK) URL</label>
                            <input type="url" disabled={!isAdmin} value={settings.mobileApkLink || ''} onChange={(e) => setSettings(s => ({...s, mobileApkLink: e.target.value}))} placeholder="Direct download link" className={inputClasses} />
                        </div>
                    </div>
                </section>

                <section>
                    <SectionHeader label="BRANDING ASSETS" />
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-10 items-start">
                        <div className="space-y-4">
                            <label className={labelClasses}>Master Logo Upload</label>
                            <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleLogoUpload} disabled={!isAdmin} />
                            <button onClick={() => fileInputRef.current?.click()} disabled={!isAdmin} className="w-full py-12 bg-slate-50 border-2 border-dashed border-slate-200 rounded-[2rem] flex flex-col items-center justify-center gap-3 hover:bg-slate-100 transition-all disabled:opacity-50">
                                <svg className="w-8 h-8 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">SUBMIT ASSET</span>
                            </button>
                        </div>
                        <div className="flex flex-col h-full">
                            <label className={labelClasses}>Visual Preview</label>
                            <div className="w-full flex-1 min-h-[140px] bg-slate-50 rounded-[2rem] border border-slate-200 flex items-center justify-center p-6 shadow-inner">
                                {settings.companyLogo && !logoError ? (
                                    <img src={settings.companyLogo} alt="Preview" className="max-h-24 object-contain grayscale opacity-60" onError={() => setLogoError(true)} />
