                {isAdmin && (
                    <div className="pt-8 border-t border-slate-50 flex justify-end">
                        <button onClick={handleSaveSettings} disabled={isSavingSettings} className="w-full sm:w-auto px-12 py-4 bg-slate-900 hover:bg-black text-white font-black rounded-2xl shadow-xl transition-all active:scale-95 disabled:opacity-50 text-[10px] uppercase tracking-[0.2em] border-t border-white/10">
                            {isSavingSettings ? 'SYNCING DATA...' : 'COMMIT CHANGES'}
                        </button>
                    </div>
                )}
             </div>
        </div>
    );
}

