import React, { useState, useEffect } from 'react';
import { User, SystemSettings } from '../types';

interface LoginViewProps {
  onLogin: (user: User) => void;
  appScriptUrl: string;
  setAppScriptUrl: (url: string) => void;
  settings: SystemSettings;
}

const LoginView: React.FC<LoginViewProps> = ({ onLogin, appScriptUrl, setAppScriptUrl, settings }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [isRegistering, setIsRegistering] = useState(false);
  const [fullName, setFullName] = useState('');
  const [position, setPosition] = useState('');
  const [logoError, setLogoError] = useState(false);
  const [showUrlSetup, setShowUrlSetup] = useState(false);
  const [tempUrl, setTempUrl] = useState(appScriptUrl);

  useEffect(() => {
    const saved = localStorage.getItem('sc_remembered_creds');
    if (saved) {
      try {
        const { u, p } = JSON.parse(atob(saved));
        setUsername(u);
        setPassword(p);
        setRememberMe(true);
      } catch (e) {
        localStorage.removeItem('sc_remembered_creds');
      }
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!appScriptUrl || !appScriptUrl.startsWith('https://script.google.com')) {
      setError("System connection required. Click the gear icon below.");
      setShowUrlSetup(true);
      return;
    }

    setError('');
    setIsLoading(true);

    try {
      const payload = isRegistering 
        ? { action: 'register_user', username, password, name: fullName, position: position, role: 'SuperAdmin' }
        : { action: 'login', username, password };

      const response = await fetch(appScriptUrl, {
        method: 'POST',
        body: JSON.stringify(payload)
      });

      const result = await response.json();

      if (result.status === 'success') {
          const rawUser = result.user;

          if (rememberMe && password) {
            const creds = btoa(JSON.stringify({ u: username, p: password }));
            localStorage.setItem('sc_remembered_creds', creds);
          } else {
            localStorage.removeItem('sc_remembered_creds');
          }

          if (isRegistering) {
              setError("Admin created. Please sign in.");
              setIsRegistering(false);
              setFullName('');
              setPosition('');
              setPassword('');
          } else {
              let safeRole: User['role'] = 'Inspector';
              const rawRole = rawUser.role ? String(rawUser.role).trim().toLowerCase() : '';

              if (rawRole === 'superadmin') safeRole = 'SuperAdmin';
              else if (rawRole === 'admin') safeRole = 'Admin';
              else if (rawRole === 'operations') safeRole = 'Operations';
              else if (rawRole === 'maintenance') safeRole = 'Maintenance';
              else if (rawRole === 'other') safeRole = 'Other';

              onLogin({ 
                ...rawUser, 
                role: safeRole, 
                position: rawUser.position || '',
                needsSetup: !rawUser.name
              });
          }
      } else if (result.code === 'NO_USERS') {
          setError("Initial setup: Create administrator.");
          setIsRegistering(true);
      } else {
          setError(result.message || "Sign in failed.");
      }

    } catch (err) {
      setError("Cannot reach server. Check internet and URL.");
    } finally {
      setIsLoading(false); 
    }
  };

  const handleSaveUrl = () => {
      if (tempUrl.startsWith('https://script.google.com')) {
          setAppScriptUrl(tempUrl);
          localStorage.setItem('safetyCheck_scriptUrl', tempUrl);
          setShowUrlSetup(false);
          setError('');
      } else {
          alert("Invalid URL. Must be a Google Apps Script endpoint.");
      }
  };

  const isUrlValid = appScriptUrl && appScriptUrl.startsWith('https://script.google.com');

  return (
    <div className="h-screen w-full bg-slate-100 flex flex-col md:flex-row font-sans text-slate-700 overflow-hidden">

      {/* Brand Panel */}
      <div className="w-full md:w-[40%] lg:w-[35%] bg-slate-900 p-8 md:p-16 flex flex-col justify-between shrink-0 border-b md:border-none shadow-2xl z-10 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-indigo-500"></div>
        <div className="flex md:block items-center justify-between">
          <div className="bg-white p-3 rounded-2xl inline-block shadow-lg">
             {settings.companyLogo && !logoError ? (
                <img src={settings.companyLogo} alt="Logo" className="h-8 sm:h-12 w-auto object-contain" onError={() => setLogoError(true)} />
             ) : (
                <div className="flex items-center gap-2 px-3">
                    <span className="font-black text-slate-900 text-2xl uppercase tracking-tighter italic">S</span>
                </div>
             )}
          </div>

          <div className="md:mt-12 text-right md:text-left">
            <h1 className="text-xl sm:text-3xl font-black text-white leading-none uppercase tracking-tighter">
                {settings.companyName || 'SAFETYCHECK'}
            </h1>
            <p className="text-indigo-400 font-black uppercase tracking-[0.4em] text-[10px] mt-2">FLEET TELEMETRY SUITE</p>
          </div>
        </div>

        <div className="mt-8 space-y-4">
            <div className="flex items-center gap-3">
                <div className={`w-3 h-3 rounded-full shadow-[0_0_12px_currentColor] ${isLoading ? 'bg-blue-400 animate-pulse' : isUrlValid ? 'bg-emerald-500' : 'bg-rose-500'} transition-colors duration-500`}></div>
                <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">
                    {isLoading ? 'EXECUTING PROCESS' : isUrlValid ? 'NODE READY' : 'CONNECTION FAULT'}
                </span>
            </div>
            <div className="hidden sm:block pt-6 border-t border-white/5">
                <span className="text-[10px] text-slate-600 font-black uppercase tracking-[0.3em]">OPERATIONS HUB v3.2.1</span>
            </div>
        </div>
      </div>

      {/* Form Panel */}
      <div className="flex-1 flex flex-col bg-white overflow-hidden relative justify-center px-8 md:px-20">
        <div className="w-full max-w-sm mx-auto">
          <div className="mb-12 text-center md:text-left">
            <h2 className="text-3xl font-black text-slate-900 tracking-tighter uppercase">
              {isRegistering ? 'PROVISIONING' : 'AUTHENTICATION'}
            </h2>
            <p className="text-slate-400 text-[11px] font-black uppercase tracking-[0.2em] mt-2">
              {isRegistering ? 'CREATE MASTER ACCOUNT' : 'ENTER SECURE CREDENTIALS'}
            </p>
          </div>

          {error && (
            <div className={`mb-8 p-5 rounded-2xl text-[11px] font-black uppercase tracking-widest border animate-fadeIn shadow-sm
              ${error.includes("created") ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
              <div className="flex items-center gap-3">
                 <svg className="w-4 h-4 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                 {error}
              </div>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-5">
            {isRegistering && (
              <div className="space-y-4 p-6 bg-slate-50 rounded-[2rem] border border-slate-100 shadow-inner">
                <input type="text" required className="w-full px-5 py-4 bg-white border border-slate-200 rounded-xl text-xs font-black uppercase tracking-widest outline-none focus:ring-4 focus:ring-indigo-50" value={fullName} onChange={e => setFullName(e.target.value)} placeholder="FULL NAME" />
                <input type="text" required className="w-full px-5 py-4 bg-white border border-slate-200 rounded-xl text-xs font-black uppercase tracking-widest outline-none focus:ring-4 focus:ring-indigo-50" value={position} onChange={e => setPosition(e.target.value)} placeholder="DESIGNATION" />
              </div>
            )}

            <div className="space-y-5">
              <input type="email" required className="w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-2xl focus:bg-white focus:ring-4 focus:ring-slate-100 outline-none font-black text-xs uppercase tracking-widest transition-all" value={username} onChange={e => setUsername(e.target.value)} placeholder="EMAIL IDENTITY" />
              <input type="password" required className="w-full px-6 py-5 bg-slate-50 border border-slate-200 rounded-2xl focus:bg-white focus:ring-4 focus:ring-slate-100 outline-none font-black text-xs uppercase tracking-widest transition-all" value={password} onChange={e => setPassword(e.target.value)} placeholder="ACCESS KEY" />
            </div>

            <div className="flex items-center justify-between px-2 pt-2">
                <label className="flex items-center gap-3 cursor-pointer select-none">
                    <input type="checkbox" className="w-5 h-5 rounded-lg border-slate-300 text-slate-900 focus:ring-0" checked={rememberMe} onChange={e => setRememberMe(e.target.checked)} />
                    <span className="text-[10px] text-slate-500 font-black uppercase tracking-widest">REMEMBER NODE</span>
                </label>
            </div>

            <div className="pt-6">
              <button type="submit" disabled={isLoading || !isUrlValid} className="w-full py-5 rounded-2xl font-black text-white bg-slate-900 hover:bg-black transition-all text-xs uppercase tracking-[0.3em] disabled:bg-slate-100 disabled:text-slate-300 shadow-xl active:scale-95 border-t border-white/10">
                {isLoading ? 'PROCESSING...' : isRegistering ? 'EXECUTE ENROLLMENT' : 'ESTABLISH SESSION'}
              </button>
            </div>
          </form>
        </div>

        {/* Setup Toggle */}
        <button onClick={() => setShowUrlSetup(!showUrlSetup)} className="absolute bottom-8 right-8 p-4 text-slate-200 hover:text-indigo-600 transition-all hover:bg-indigo-50 rounded-2xl">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"/><circle cx="12" cy="12" r="3"/></svg>
        </button>

        {showUrlSetup && (
            <div className="absolute inset-0 bg-white/98 backdrop-blur-md z-20 flex flex-col items-center justify-center p-10 animate-fadeIn">
                <div className="w-full max-w-sm space-y-8 text-center">
                    <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">DATA ENDPOINT</h3>
                    <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">APP SCRIPT INTERFACE</label>
                        <input type="text" className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl text-[10px] font-mono outline-none focus:ring-4 focus:ring-indigo-50" placeholder="https://script.google.com/..." value={tempUrl} onChange={e => setTempUrl(e.target.value)} />
                    </div>
                    <div className="flex gap-4">
                        <button onClick={() => setShowUrlSetup(false)} className="flex-1 py-4 text-[10px] font-black text-slate-400 hover:text-slate-900 uppercase tracking-widest transition-all">CANCEL</button>
                        <button onClick={handleSaveUrl} className="flex-1 py-4 bg-slate-900 text-white font-black rounded-2xl text-[10px] uppercase tracking-widest shadow-xl">LINK NODE</button>
                    </div>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

