import { useState, useEffect, useRef } from 'react';
import { AppNotification, User } from '../types';

const MAX_NOTIFICATIONS = 50; 
const POLLING_INTERVAL = 60000; // 1 minute
const ALERT_MAX_AGE_MS = 24 * 60 * 60 * 1000; // 24 Hours - Keep it fresh

export const useNotifications = (appScriptUrl: string, currentUser: User | null, showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void) => {
    const [notifications, setNotifications] = useState<AppNotification[]>([]);
    const [readNotificationIds, setReadNotificationIds] = useState<string[]>([]);
    const [dismissedNotificationIds, setDismissedNotificationIds] = useState<string[]>([]);
    const [notifiedIds, setNotifiedIds] = useState<string[]>([]); 

    // Use Refs to handle the true dismissal state during async polling
    const dismissedRef = useRef<string[]>([]);
    const readRef = useRef<string[]>([]);
    const notifiedRef = useRef<string[]>([]);
    const pollingRef = useRef<number | null>(null);

    // Synchronize state with refs for background logic
    useEffect(() => { dismissedRef.current = dismissedNotificationIds; }, [dismissedNotificationIds]);
    useEffect(() => { readRef.current = readNotificationIds; }, [readNotificationIds]);
    useEffect(() => { notifiedRef.current = notifiedIds; }, [notifiedIds]);

    useEffect(() => {
        if (!currentUser) {
            if (pollingRef.current) window.clearInterval(pollingRef.current);
            return;
        }

        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        const savedRead = localStorage.getItem(`sc_read_notifications_${userPrefix}`);
        const savedDismissed = localStorage.getItem(`sc_dismissed_notifications_${userPrefix}`);
        const savedNotified = localStorage.getItem(`sc_pop_history_${userPrefix}`);

        const initialRead = savedRead ? JSON.parse(savedRead) : [];
        const initialDismissed = savedDismissed ? JSON.parse(savedDismissed) : [];
        const initialNotified = savedNotified ? JSON.parse(savedNotified) : [];

        setReadNotificationIds(initialRead);
        setDismissedNotificationIds(initialDismissed);
        setNotifiedIds(initialNotified);

        fetchNotifications();
        pollingRef.current = window.setInterval(fetchNotifications, POLLING_INTERVAL);

        return () => {
            if (pollingRef.current) window.clearInterval(pollingRef.current);
        };
    }, [currentUser, appScriptUrl]);

    const saveState = (type: 'read' | 'dismissed' | 'notified', ids: string[]) => {
        if (!currentUser) return;
        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        const key = type === 'read' ? `sc_read_notifications_${userPrefix}` : 
                    type === 'dismissed' ? `sc_dismissed_notifications_${userPrefix}` : 
                    `sc_pop_history_${userPrefix}`;
        localStorage.setItem(key, JSON.stringify(ids));

        if (type === 'read') setReadNotificationIds(ids);
        else if (type === 'dismissed') setDismissedNotificationIds(ids);
        else if (type === 'notified') setNotifiedIds(ids);
    };

    const fetchNotifications = async () => {
        if (!appScriptUrl || !navigator.onLine || !currentUser) return;

        try {
            const response = await fetch(`${appScriptUrl}?t=${Date.now()}`);
            if (!response.ok) return;

            const text = await response.text();
            if (!text || text.trim().startsWith('<')) return;

            const json = JSON.parse(text);
            const serverAcknowledgements = (json['Acknowledgements'] || []).map((id: any) => String(id));
            const now = Date.now();

            let allAlerts: AppNotification[] = [];

            const isDismissed = (id: string) => dismissedRef.current.includes(id) || serverAcknowledgements.includes(id);
            const isRead = (id: string) => readRef.current.includes(id);

            const processRows = (rows: any[], moduleName: string): AppNotification[] => {
                if (!Array.isArray(rows) || rows.length <= 1) return [];
                const rateIndex = moduleName === 'General' ? 8 : 9;
                const truckIndex = 2;

                return rows.slice(Math.max(1, rows.length - 50)).map((row: any[]) => {
                    const tsRaw = String(row[1]); 
                    const tsParsed = Date.parse(tsRaw);
                    const truck = String(row[truckIndex] || 'UNIT').trim().toUpperCase();
                    const rate = Number(row[rateIndex]);

                    // Generate a truly immutable ID
                    const alertId = `V_${moduleName}_${tsParsed}_${truck}`.replace(/\s+/g, '');

                    if (isDismissed(alertId) || isNaN(tsParsed) || (now - tsParsed > ALERT_MAX_AGE_MS)) {
                        return null;
                    }

                    if (rate <= 3) {
                        return {
                            id: alertId,
                            title: rate <= 2 ? `CRITICAL: ${truck}` : `WARNING: ${truck}`,
                            message: `${moduleName} Audit: Rated ${rate}/5`,
                            type: rate <= 2 ? 'critical' : 'warning',
                            timestamp: tsRaw,
                            read: isRead(alertId),
                            module: moduleName
                        };
                    }
                    return null;
                }).filter(n => n !== null) as AppNotification[];
            };

            // Process sheets
            ['General', 'Petroleum', 'Petroleum_V2', 'Acid'].forEach(sheet => {
                if (json[sheet]) allAlerts = [...allAlerts, ...processRows(json[sheet], sheet)];
            });

            // Process System Notifications
            const systemRows = json['SystemNotification'] || [];
            if (Array.isArray(systemRows) && systemRows.length > 1) {
                const userEmail = currentUser.username.toLowerCase().trim();
                const userRole = currentUser.role.toLowerCase().trim();

                systemRows.forEach((row: any[]) => {
                    const notifId = String(row[0]);
                    const recipient = String(row[1]).trim().toLowerCase();
                    const isReadOnServer = String(row[5]).toUpperCase() === 'TRUE';

                    if (isDismissed(notifId) || isReadOnServer) return;

                    if (recipient === userEmail || recipient === userRole || recipient === 'all') {
                        allAlerts.push({
                            id: notifId,
                            title: 'SYSTEM ALERT',
                            message: String(row[3]),
                            type: String(row[2]).toLowerCase() as any || 'info',
                            timestamp: row[4],
                            read: isRead(notifId),
                            actionLink: row[6],
                            isServerEvent: true
                        });
                    }
                });
            }

            allAlerts.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
            const finalAlerts = allAlerts.slice(0, MAX_NOTIFICATIONS);

            // Handle Pop-ups: Only for items not in notifiedRef AND not in dismissedRef
            const newForToast = finalAlerts.filter(a => 
                !notifiedRef.current.includes(a.id) && 
                !a.read && 
                !dismissedRef.current.includes(a.id)
            );

            if (newForToast.length > 0) {
                const latest = newForToast[0];
                showToast(latest.message, latest.type === 'critical' ? 'error' : 'info');
                const updatedNotified = [...new Set([...notifiedRef.current, ...newForToast.map(a => a.id)])];
                saveState('notified', updatedNotified);
            }

            setNotifications(finalAlerts);
        } catch (e) {
            console.warn("Notification sync delayed.");
        }
    };

    const handleMarkNotificationRead = async (id: string, onNavigate?: (module: string) => void) => {
        setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n));
        saveState('read', [...new Set([...readRef.current, id])]);

        const target = notifications.find(n => n.id === id);
        if (target?.actionLink && onNavigate) onNavigate(target.actionLink);
    };

    const handleDismissNotification = (id: string) => {
        setNotifications(prev => prev.filter(n => n.id !== id));
        saveState('dismissed', [...new Set([...dismissedRef.current, id])]);
        saveState('notified', [...new Set([...notifiedRef.current, id])]);
    };

    const handleClearAllNotifications = () => {
        const allIds = notifications.map(n => n.id);
        saveState('dismissed', [...new Set([...dismissedRef.current, ...allIds])]);
        saveState('notified', [...new Set([...notifiedRef.current, ...allIds])]);
        setNotifications([]);
    };

    return {
        notifications,
        handleMarkNotificationRead,
        handleDismissNotification,
        handleClearAllNotifications,
        fetchNotifications
    };
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { AppNotification } from '../../types';

interface NotificationCenterProps {
    id?: string;
    notifications: AppNotification[];
    onMarkAsRead: (id: string) => void;
    onDismiss: (id: string) => void;
    onClearAll: () => void;
    onAcknowledge?: (id: string) => void; 
    canAcknowledge?: boolean;
}

const NotificationCenter: React.FC<NotificationCenterProps> = ({ 
    id,
    notifications, 
    onMarkAsRead, 
    onDismiss, 
    onClearAll,
}) => {
    const [isOpen, setIsOpen] = useState(false);
    const [activeFilter, setActiveFilter] = useState<'all' | 'unread' | 'critical'>('all');
    const wrapperRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, [wrapperRef]);

    const unreadCount = notifications.filter(n => !n.read).length;
    const criticalCount = notifications.filter(n => !n.read && n.type === 'critical').length;

    const filteredNotifications = useMemo(() => {
        let filtered = [...notifications];
        if (activeFilter === 'unread') filtered = filtered.filter(n => !n.read);
        else if (activeFilter === 'critical') filtered = filtered.filter(n => n.type === 'critical');
        return filtered;
    }, [notifications, activeFilter]);

    const getRelativeTime = (isoString: string) => {
        const date = new Date(isoString);
        const now = new Date();
        const diffInSeconds = Math.floor((now.getTime() - date.getTime()) / 1000);
        if (diffInSeconds < 60) return 'Just now';
        if (diffInSeconds < 3600) return `${Math.floor(diffInSeconds / 60)}m ago`;
        if (diffInSeconds < 86400) return `${Math.floor(diffInSeconds / 3600)}h ago`;
        return date.toLocaleDateString([], { month: 'short', day: 'numeric' });
    };

    const getIcon = (type: string) => {
        const iconClasses = "w-9 h-9 rounded-xl flex items-center justify-center shrink-0 border shadow-sm transition-all";
        switch(type) {
            case 'critical': 
                return <div className={`${iconClasses} bg-rose-50 text-rose-600 border-rose-100`}><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg></div>;
            case 'success':
                return <div className={`${iconClasses} bg-emerald-50 text-emerald-600 border-emerald-100`}><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M5 13l4 4L19 7" /></svg></div>;
            default:
                return <div className={`${iconClasses} bg-indigo-50 text-indigo-600 border-indigo-100`}><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></div>;
        }
    };

    return (
        <div className="relative" ref={wrapperRef}>
            <button 
                id={id}
                onClick={() => setIsOpen(!isOpen)}
                className={`relative p-2 rounded-xl transition-all duration-300 group
                    ${isOpen ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-900 hover:bg-slate-50'}
                `}
            >
                <svg className="w-5 h-5 group-hover:rotate-12 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                {unreadCount > 0 && (
                    <span className="absolute -top-1 -right-1 flex h-4 w-4">
                        <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${criticalCount > 0 ? 'bg-rose-400' : 'bg-indigo-400'}`}></span>
                        <span className={`relative inline-flex rounded-full h-4 w-4 text-[8px] font-bold text-white items-center justify-center border-2 border-white shadow-sm ${criticalCount > 0 ? 'bg-rose-600' : 'bg-indigo-600'}`}>
                            {unreadCount}
                        </span>
                    </span>
                )}
            </button>

            {isOpen && (
                <div className="fixed inset-x-4 bottom-4 top-20 sm:top-auto sm:bottom-auto sm:absolute sm:right-0 sm:inset-x-auto sm:mt-4 w-auto sm:w-[400px] bg-white rounded-[2rem] sm:rounded-2xl shadow-2xl ring-1 ring-black/5 z-[100] flex flex-col overflow-hidden animate-slideUp origin-bottom sm:origin-top-right">

                    {/* Header */}
                    <div className="p-6 border-b border-slate-50 flex justify-between items-center bg-white shrink-0">
                        <div>
                            <h3 className="text-lg font-bold text-slate-900 tracking-tight">Notifications</h3>
                            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest mt-0.5">Fleet Activity Monitor</p>
                        </div>
                        <button 
                            onClick={onClearAll} 
                            className="px-4 py-2 bg-slate-50 hover:bg-rose-50 text-slate-500 hover:text-rose-600 rounded-xl transition-all text-[10px] font-bold uppercase tracking-widest border border-slate-100"
                        >
                            Clear All
                        </button>
                    </div>

                    {/* Filter Tabs */}
                    <div className="flex bg-slate-50/50 p-1 border-b border-slate-50 shrink-0">
                        {['all', 'unread', 'critical'].map(f => (
                            <button 
                                key={f} 
                                onClick={() => setActiveFilter(f as any)}
                                className={`flex-1 py-2 text-[10px] font-bold uppercase tracking-widest transition-all rounded-lg
                                    ${activeFilter === f ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}
                                `}
                            >
                                {f}
                            </button>
                        ))}
                    </div>

                    {/* List Area - Zero Scroll container logic */}
                    <div className="flex-1 overflow-y-auto scrollbar-hide bg-white divide-y divide-slate-50 max-h-[50vh] sm:max-h-[400px]">
                        {filteredNotifications.length === 0 ? (
                            <div className="py-20 text-center flex flex-col items-center">
                                <div className="w-12 h-12 bg-slate-50 rounded-full flex items-center justify-center mb-4 border border-slate-100 text-slate-200">
                                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M5 13l4 4L19 7" strokeWidth="3" /></svg>
                                </div>
                                <p className="text-xs font-medium text-slate-400">Your archive is clear</p>
                            </div>
                        ) : (
                            filteredNotifications.map(n => (
                                <div 
                                    key={n.id} 
                                    className={`p-4 sm:p-5 transition-all relative group cursor-pointer hover:bg-slate-50/50
                                        ${!n.read ? 'bg-indigo-50/10' : 'bg-white'}
                                    `}
                                    onClick={() => onMarkAsRead(n.id)}
                                >
                                    <div className="flex gap-4">
                                        {getIcon(n.type)}
                                        <div className="flex-1 min-w-0">
                                            <div className="flex justify-between items-start mb-0.5">
                                                <h4 className={`text-xs font-bold truncate pr-6 ${n.type === 'critical' ? 'text-rose-600' : 'text-slate-900'}`}>
                                                    {n.title}
                                                </h4>
                                                <span className="text-[9px] font-medium text-slate-400 whitespace-nowrap bg-slate-100 px-1.5 py-0.5 rounded">
                                                    {getRelativeTime(n.timestamp)}
                                                </span>
                                            </div>
                                            <p className="text-[11px] font-medium text-slate-500 leading-relaxed line-clamp-2">
                                                {n.message}
                                            </p>
                                        </div>
                                    </div>

                                    <button 
                                        onClick={(e) => { e.stopPropagation(); onDismiss(n.id); }}
                                        className="absolute top-4 right-4 p-1.5 text-slate-200 hover:text-rose-500 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                                    >
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M6 18L18 6M6 6l12 12" /></svg>
                                    </button>
                                </div>
                            ))
                        )}
                    </div>

                    <div className="p-3 bg-slate-50 border-t border-slate-100 shrink-0 text-center">
                         <p className="text-[9px] font-medium text-slate-400 uppercase tracking-[0.2em]">Automated Intelligence Suite v4.0</p>
                    </div>
                </div>
            )}
        </div>
    );
};

export default NotificationCenter;

import React from 'react';

const Toast = ({ message, type, onClose }: { message: string, type: 'success' | 'error' | 'info' | 'warning', onClose: () => void }) => {
    const configs = {
        success: { 
            bg: 'bg-emerald-950', 
            border: 'border-emerald-500/50', 
            icon: <svg className="w-5 h-5 text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M5 13l4 4L19 7" /></svg>,
            label: 'SUCCESS'
        },
        error: { 
            bg: 'bg-rose-950', 
            border: 'border-rose-500/50', 
            icon: <svg className="w-5 h-5 text-rose-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg>,
            label: 'CRITICAL'
        },
        info: { 
            bg: 'bg-slate-900', 
            border: 'border-indigo-500/50', 
            icon: <svg className="w-5 h-5 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>,
            label: 'SYSTEM'
        },
        warning: { 
            bg: 'bg-amber-950', 
            border: 'border-amber-500/50', 
            icon: <svg className="w-5 h-5 text-amber-400" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>,
            label: 'ALERT'
        }
    };

    const config = configs[type];

    return (
        <div className="fixed top-4 left-4 right-4 sm:left-auto sm:right-6 sm:max-w-md z-[1000] animate-fadeIn no-print">
            <div className={`${config.bg} ${config.border} border-l-4 rounded-xl shadow-2xl p-4 flex items-center gap-4 relative overflow-hidden group`}>
                <div className="shrink-0 bg-white/5 p-2 rounded-lg border border-white/10 shadow-inner">
                    {config.icon}
                </div>

                <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-0.5">
                        <span className={`text-[9px] font-bold uppercase tracking-widest ${type === 'success' ? 'text-emerald-400' : type === 'error' ? 'text-rose-400' : type === 'info' ? 'text-indigo-400' : 'text-amber-400'}`}>
                            {config.label}
                        </span>
                    </div>
                    <p className="text-white text-xs font-medium leading-relaxed truncate opacity-90">
                        {message}
                    </p>
                </div>

                <button 
                    onClick={onClose} 
                    className="p-1.5 text-white/30 hover:text-white hover:bg-white/10 rounded-lg transition-all active:scale-90"
                >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
            </div>
        </div>
    );
};

export default Toast;

import { useState, useEffect, useRef } from 'react';
import { AppNotification, User } from '../types';

const MAX_NOTIFICATIONS = 50; 
const POLLING_INTERVAL = 60000; // 1 minute
const ALERT_MAX_AGE_MS = 24 * 60 * 60 * 1000; // 24 Hours - Keep it fresh

export const useNotifications = (appScriptUrl: string, currentUser: User | null, showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void) => {
    const [notifications, setNotifications] = useState<AppNotification[]>([]);
    const [readNotificationIds, setReadNotificationIds] = useState<string[]>([]);
    const [dismissedNotificationIds, setDismissedNotificationIds] = useState<string[]>([]);
    const [notifiedIds, setNotifiedIds] = useState<string[]>([]); 

    // Use Refs to handle the true dismissal state during async polling
    const dismissedRef = useRef<string[]>([]);
    const readRef = useRef<string[]>([]);
    const notifiedRef = useRef<string[]>([]);
    const pollingRef = useRef<number | null>(null);

    // Synchronize state with refs for background logic
    useEffect(() => { dismissedRef.current = dismissedNotificationIds; }, [dismissedNotificationIds]);
    useEffect(() => { readRef.current = readNotificationIds; }, [readNotificationIds]);
    useEffect(() => { notifiedRef.current = notifiedIds; }, [notifiedIds]);

    useEffect(() => {
        if (!currentUser) {
            if (pollingRef.current) window.clearInterval(pollingRef.current);
            return;
        }

        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        const savedRead = localStorage.getItem(`sc_read_notifications_${userPrefix}`);
        const savedDismissed = localStorage.getItem(`sc_dismissed_notifications_${userPrefix}`);
        const savedNotified = localStorage.getItem(`sc_pop_history_${userPrefix}`);

        const initialRead = savedRead ? JSON.parse(savedRead) : [];
        const initialDismissed = savedDismissed ? JSON.parse(savedDismissed) : [];
        const initialNotified = savedNotified ? JSON.parse(savedNotified) : [];

        setReadNotificationIds(initialRead);
        setDismissedNotificationIds(initialDismissed);
        setNotifiedIds(initialNotified);

        fetchNotifications();
        pollingRef.current = window.setInterval(fetchNotifications, POLLING_INTERVAL);

        return () => {
            if (pollingRef.current) window.clearInterval(pollingRef.current);
        };
    }, [currentUser, appScriptUrl]);

    const saveState = (type: 'read' | 'dismissed' | 'notified', ids: string[]) => {
        if (!currentUser) return;
        const userPrefix = currentUser.username.replace(/[^a-z0-9]/gi, '_') + '_';
        const key = type === 'read' ? `sc_read_notifications_${userPrefix}` : 
                    type === 'dismissed' ? `sc_dismissed_notifications_${userPrefix}` : 
                    `sc_pop_history_${userPrefix}`;
        localStorage.setItem(key, JSON.stringify(ids));

        if (type === 'read') setReadNotificationIds(ids);
        else if (type === 'dismissed') setDismissedNotificationIds(ids);
        else if (type === 'notified') setNotifiedIds(ids);
    };

    const fetchNotifications = async () => {
        if (!appScriptUrl || !navigator.onLine || !currentUser) return;

        try {
            const response = await fetch(`${appScriptUrl}?t=${Date.now()}`);
            if (!response.ok) return;

            const text = await response.text();
            if (!text || text.trim().startsWith('<')) return;

            const json = JSON.parse(text);
            const serverAcknowledgements = (json['Acknowledgements'] || []).map((id: any) => String(id));
            const now = Date.now();

            let allAlerts: AppNotification[] = [];

            const isDismissed = (id: string) => dismissedRef.current.includes(id) || serverAcknowledgements.includes(id);
            const isRead = (id: string) => readRef.current.includes(id);

            const processRows = (rows: any[], moduleName: string): AppNotification[] => {
                if (!Array.isArray(rows) || rows.length <= 1) return [];
                const rateIndex = moduleName === 'General' ? 8 : 9;
                const truckIndex = 2;

                return rows.slice(Math.max(1, rows.length - 50)).map((row: any[]) => {
                    const tsRaw = String(row[1]); 
                    const tsParsed = Date.parse(tsRaw);
                    const truck = String(row[truckIndex] || 'UNIT').trim().toUpperCase();
                    const rate = Number(row[rateIndex]);

                    // Generate a truly immutable ID
                    const alertId = `V_${moduleName}_${tsParsed}_${truck}`.replace(/\s+/g, '');

                    if (isDismissed(alertId) || isNaN(tsParsed) || (now - tsParsed > ALERT_MAX_AGE_MS)) {
                        return null;
                    }

                    if (rate <= 3) {
                        return {
                            id: alertId,
                            title: rate <= 2 ? `CRITICAL: ${truck}` : `WARNING: ${truck}`,
                            message: `${moduleName} Audit: Rated ${rate}/5`,
                            type: rate <= 2 ? 'critical' : 'warning',
                            timestamp: tsRaw,
                            read: isRead(alertId),
                            module: moduleName
                        };
                    }
                    return null;
                }).filter(n => n !== null) as AppNotification[];
            };

            // Process sheets
            ['General', 'Petroleum', 'Petroleum_V2', 'Acid'].forEach(sheet => {
                if (json[sheet]) allAlerts = [...allAlerts, ...processRows(json[sheet], sheet)];
            });

            // Process System Notifications
            const systemRows = json['SystemNotification'] || [];
            if (Array.isArray(systemRows) && systemRows.length > 1) {
                const userEmail = currentUser.username.toLowerCase().trim();
                const userRole = currentUser.role.toLowerCase().trim();

                systemRows.forEach((row: any[]) => {
                    const notifId = String(row[0]);
                    const recipient = String(row[1]).trim().toLowerCase();
                    const isReadOnServer = String(row[5]).toUpperCase() === 'TRUE';

                    if (isDismissed(notifId) || isReadOnServer) return;

                    if (recipient === userEmail || recipient === userRole || recipient === 'all') {
                        allAlerts.push({
                            id: notifId,
                            title: 'SYSTEM ALERT',
                            message: String(row[3]),
                            type: String(row[2]).toLowerCase() as any || 'info',
                            timestamp: row[4],
                            read: isRead(notifId),
                            actionLink: row[6],
                            isServerEvent: true
                        });
                    }
                });
            }

            allAlerts.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
            const finalAlerts = allAlerts.slice(0, MAX_NOTIFICATIONS);

            // Handle Pop-ups: Only for items not in notifiedRef AND not in dismissedRef
            const newForToast = finalAlerts.filter(a => 
                !notifiedRef.current.includes(a.id) && 
                !a.read && 
                !dismissedRef.current.includes(a.id)
            );

            if (newForToast.length > 0) {
                const latest = newForToast[0];
                showToast(latest.message, latest.type === 'critical' ? 'error' : 'info');
                const updatedNotified = [...new Set([...notifiedRef.current, ...newForToast.map(a => a.id)])];
                saveState('notified', updatedNotified);
            }

            setNotifications(finalAlerts);
        } catch (e) {
            console.warn("Notification sync delayed.");
        }
    };

    const handleMarkNotificationRead = async (id: string, onNavigate?: (module: string) => void) => {
        setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n));
        saveState('read', [...new Set([...readRef.current, id])]);

        const target = notifications.find(n => n.id === id);
        if (target?.actionLink && onNavigate) onNavigate(target.actionLink);
    };

    const handleDismissNotification = (id: string) => {
        setNotifications(prev => prev.filter(n => n.id !== id));
        saveState('dismissed', [...new Set([...dismissedRef.current, id])]);
        saveState('notified', [...new Set([...notifiedRef.current, id])]);
    };

    const handleClearAllNotifications = () => {
        const allIds = notifications.map(n => n.id);
        saveState('dismissed', [...new Set([...dismissedRef.current, ...allIds])]);
        saveState('notified', [...new Set([...notifiedRef.current, ...allIds])]);
        setNotifications([]);
    };

    // Fix: Added handleGlobalAcknowledge function to support system-wide notification dismissal
    const handleGlobalAcknowledge = async (id: string) => {
        if (!appScriptUrl || !currentUser) return;

        // Optimistic UI update - hide from current user session immediately
        handleDismissNotification(id);

        try {
            // Sends a request to the backend to mark this specific notification as acknowledged system-wide
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'acknowledge_notification',
                    notificationId: id,
                    user: currentUser.username
                }),
                mode: 'no-cors'
            });
            showToast("Global acknowledgement synced.", "success");
        } catch (e) {
            console.warn("Server acknowledgement failed, kept in local dismissal list.");
        }
    };

    return {
        notifications,
        handleMarkNotificationRead,
        handleDismissNotification,
        handleClearAllNotifications,
        handleGlobalAcknowledge, // Fix: Returning the new handler to match App.tsx usage
        fetchNotifications
    };
};

import { useState, useRef, useEffect, useMemo } from 'react';
import { AppNotification } from '../../types';

interface NotificationCenterProps {
    id?: string;
    notifications: AppNotification[];
    onMarkAsRead: (id: string) => void;
    onDismiss: (id: string) => void;
    onClearAll: () => void;
    onAcknowledge?: (id: string) => void; 
    canAcknowledge?: boolean;
}

const NotificationCenter: React.FC<NotificationCenterProps> = ({ 
    id,
    notifications, 
    onMarkAsRead, 
    onDismiss, 
    onClearAll,
    onAcknowledge, // Fix: Added missing prop destructuring
    canAcknowledge // Fix: Added missing prop destructuring
}) => {
    const [isOpen, setIsOpen] = useState(false);
    const [activeFilter, setActiveFilter] = useState<'all' | 'unread' | 'critical'>('all');
    const wrapperRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, [wrapperRef]);

    const unreadCount = notifications.filter(n => !n.read).length;
    const criticalCount = notifications.filter(n => !n.read && n.type === 'critical').length;

    const filteredNotifications = useMemo(() => {
        let filtered = [...notifications];
        if (activeFilter === 'unread') filtered = filtered.filter(n => !n.read);
        else if (activeFilter === 'critical') filtered = filtered.filter(n => n.type === 'critical');
        return filtered;
    }, [notifications, activeFilter]);

    const getRelativeTime = (isoString: string) => {
        const date = new Date(isoString);
        const now = new Date();
        const diffInSeconds = Math.floor((now.getTime() - date.getTime()) / 1000);
        if (diffInSeconds < 60) return 'Just now';
        if (diffInSeconds < 3600) return `${Math.floor(diffInSeconds / 60)}m ago`;
        if (diffInSeconds < 86400) return `${Math.floor(diffInSeconds / 3600)}h ago`;
        return date.toLocaleDateString([], { month: 'short', day: 'numeric' });
    };

    const getIcon = (type: string) => {
        const iconClasses = "w-9 h-9 rounded-xl flex items-center justify-center shrink-0 border shadow-sm transition-all";
        switch(type) {
            case 'critical': 
                return <div className={`${iconClasses} bg-rose-50 text-rose-600 border-rose-100`}><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg></div>;
            case 'success':
                return <div className={`${iconClasses} bg-emerald-50 text-emerald-600 border-emerald-100`}><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M5 13l4 4L19 7" /></svg></div>;
            default:
                return <div className={`${iconClasses} bg-indigo-50 text-indigo-600 border-indigo-100`}><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg></div>;
        }
    };

    return (
        <div className="relative" ref={wrapperRef}>
            <button 
                id={id}
                onClick={() => setIsOpen(!isOpen)}
                className={`relative p-2 rounded-xl transition-all duration-300 group
                    ${isOpen ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-900 hover:bg-slate-50'}
                `}
            >
                <svg className="w-5 h-5 group-hover:rotate-12 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                {unreadCount > 0 && (
                    <span className="absolute -top-1 -right-1 flex h-4 w-4">
                        <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${criticalCount > 0 ? 'bg-rose-400' : 'bg-indigo-400'}`}></span>
                        <span className={`relative inline-flex rounded-full h-4 w-4 text-[8px] font-bold text-white items-center justify-center border-2 border-white shadow-sm ${criticalCount > 0 ? 'bg-rose-600' : 'bg-indigo-600'}`}>
                            {unreadCount}
                        </span>
                    </span>
                )}
            </button>

            {isOpen && (
                <div className="fixed inset-x-4 bottom-4 top-20 sm:top-auto sm:bottom-auto sm:absolute sm:right-0 sm:inset-x-auto sm:mt-4 w-auto sm:w-[400px] bg-white rounded-[2rem] sm:rounded-2xl shadow-2xl ring-1 ring-black/5 z-[100] flex flex-col overflow-hidden animate-slideUp origin-bottom sm:origin-top-right">

                    {/* Header */}
                    <div className="p-6 border-b border-slate-50 flex justify-between items-center bg-white shrink-0">
                        <div>
                            <h3 className="text-lg font-bold text-slate-900 tracking-tight">Notifications</h3>
                            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest mt-0.5">Fleet Activity Monitor</p>
                        </div>
                        <button 
                            onClick={onClearAll} 
                            className="px-4 py-2 bg-slate-50 hover:bg-rose-50 text-slate-500 hover:text-rose-600 rounded-xl transition-all text-[10px] font-bold uppercase tracking-widest border border-slate-100"
                        >
                            Clear All
                        </button>
                    </div>

                    {/* Filter Tabs */}
                    <div className="flex bg-slate-50/50 p-1 border-b border-slate-50 shrink-0">
                        {['all', 'unread', 'critical'].map(f => (
                            <button 
                                key={f} 
                                onClick={() => setActiveFilter(f as any)}
                                className={`flex-1 py-2 text-[10px] font-bold uppercase tracking-widest transition-all rounded-lg
                                    ${activeFilter === f ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}
                                `}
                            >
                                {f}
                            </button>
                        ))}
                    </div>

                    {/* List Area - Zero Scroll container logic */}
                    <div className="flex-1 overflow-y-auto scrollbar-hide bg-white divide-y divide-slate-50 max-h-[50vh] sm:max-h-[400px]">
                        {filteredNotifications.length === 0 ? (
                            <div className="py-20 text-center flex flex-col items-center">
                                <div className="w-12 h-12 bg-slate-50 rounded-full flex items-center justify-center mb-4 border border-slate-100 text-slate-200">
                                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M5 13l4 4L19 7" strokeWidth="3" /></svg>
                                </div>
                                <p className="text-xs font-medium text-slate-400">Your archive is clear</p>
                            </div>
                        ) : (
                            filteredNotifications.map(n => (
                                <div 
                                    key={n.id} 
                                    className={`p-4 sm:p-5 transition-all relative group cursor-pointer hover:bg-slate-50/50
                                        ${!n.read ? 'bg-indigo-50/10' : 'bg-white'}
                                    `}
                                    onClick={() => onMarkAsRead(n.id)}
                                >
                                    <div className="flex gap-4">
                                        {getIcon(n.type)}
                                        <div className="flex-1 min-w-0">
                                            <div className="flex justify-between items-start mb-0.5">
                                                <h4 className={`text-xs font-bold truncate pr-6 ${n.type === 'critical' ? 'text-rose-600' : 'text-slate-900'}`}>
                                                    {n.title}
                                                </h4>
                                                <span className="text-[9px] font-medium text-slate-400 whitespace-nowrap bg-slate-100 px-1.5 py-0.5 rounded">
                                                    {getRelativeTime(n.timestamp)}
                                                </span>
                                            </div>
                                            <p className="text-[11px] font-medium text-slate-500 leading-relaxed line-clamp-2">
                                                {n.message}
                                            </p>

                                            {/* Fix: Display Acknowledge button for Admins on critical alerts */}
                                            {canAcknowledge && n.type === 'critical' && onAcknowledge && (
                                                <button 
                                                    onClick={(e) => { e.stopPropagation(); onAcknowledge(n.id); }}
                                                    className="mt-3 px-3 py-1.5 bg-slate-900 text-white text-[8px] font-black uppercase tracking-widest rounded-lg hover:bg-black transition-all shadow-sm"
                                                >
                                                    Acknowledge Global
                                                </button>
                                            )}
                                        </div>
                                    </div>

                                    <button 
                                        onClick={(e) => { e.stopPropagation(); onDismiss(n.id); }}
                                        className="absolute top-4 right-4 p-1.5 text-slate-200 hover:text-rose-500 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                                    >
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M6 18L18 6M6 6l12 12" /></svg>
                                    </button>
                                </div>
                            ))
                        )}
                    </div>

                    <div className="p-3 bg-slate-50 border-t border-slate-100 shrink-0 text-center">
                         <p className="text-[9px] font-medium text-slate-400 uppercase tracking-[0.2em]">Automated Intelligence Suite v4.0</p>
                    </div>
                </div>
            )}
        </div>
    );
};

export default NotificationCenter;

import React, { useState, useEffect } from 'react';
import { User, SystemSettings } from '../types';

interface LoginViewProps {
  onLogin: (user: User) => void;
  appScriptUrl: string;
  setAppScriptUrl: (url: string) => void;
  settings: SystemSettings;
}

const LoginView: React.FC<LoginViewProps> = ({ onLogin, appScriptUrl, setAppScriptUrl, settings }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [isRegistering, setIsRegistering] = useState(false);
  const [fullName, setFullName] = useState('');
  const [position, setPosition] = useState('');
  const [logoError, setLogoError] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('sc_remembered_creds');
    if (saved) {
      try {
        const { u, p } = JSON.parse(atob(saved));
        setUsername(u);
        setPassword(p);
        setRememberMe(true);
      } catch (e) {
        localStorage.removeItem('sc_remembered_creds');
      }
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!appScriptUrl || !appScriptUrl.startsWith('https://script.google.com')) {
      setError("System connection error. Please contact your administrator.");
      return;
    }

    setError('');
    setIsLoading(true);

    try {
      const payload = isRegistering 
        ? { action: 'register_user', username, password, name: fullName, position: position, role: 'SuperAdmin' }
        : { action: 'login', username, password };

      const response = await fetch(appScriptUrl, {
        method: 'POST',
        body: JSON.stringify(payload)
      });

      const result = await response.json();

      if (result.status === 'success') {
          const rawUser = result.user;

          if (rememberMe && password) {
            const creds = btoa(JSON.stringify({ u: username, p: password }));
            localStorage.setItem('sc_remembered_creds', creds);
          } else {
            localStorage.removeItem('sc_remembered_creds');
          }

          if (isRegistering) {
              setError("Admin created. Please sign in.");
              setIsRegistering(false);
              setFullName('');
              setPosition('');
              setPassword('');
          } else {
              let safeRole: User['role'] = 'Inspector';
              const rawRole = rawUser.role ? String(rawRole).trim().toLowerCase() : '';

              if (rawRole === 'superadmin') safeRole = 'SuperAdmin';
              else if (rawRole === 'admin') safeRole = 'Admin';
              else if (rawRole === 'operations') safeRole = 'Operations';
              else if (rawRole === 'maintenance') safeRole = 'Maintenance';
              else if (rawRole === 'other') safeRole = 'Other';

              onLogin({ 
                ...rawUser, 
                role: safeRole, 
                position: rawUser.position || '',
                needsSetup: !rawUser.name
              });
          }
      } else if (result.code === 'NO_USERS') {
          setError("Initial setup: Create administrator.");
          setIsRegistering(true);
      } else {
          setError(result.message || "Sign in failed.");
      }

    } catch (err) {
      setError("Cannot reach server. Check internet connection.");
    } finally {
      setIsLoading(false); 
    }
  };

  const isUrlValid = appScriptUrl && appScriptUrl.startsWith('https://script.google.com');

  return (
