import {} from '../types';

const CODE_CONTROLLER = `
function doPost(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(30000); 
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const body = e.postData ? JSON.parse(e.postData.contents) : {};
    return routeRequest(ss, body);
  } catch (err) {
    return ResponseBuilder.error(err.toString());
  } finally {
    lock.releaseLock();
  }
}

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  return DataHandlers.handleGetRequest(ss);
}

function routeRequest(ss, body) {
  const action = body.action;
  const routes = {
    'login': () => AuthHandlers.handleLogin(ss, body),
    'register_user': () => AuthHandlers.handleRegisterUser(ss, body),
    'get_users': () => AuthHandlers.handleGetUsers(ss),
    'delete_user': () => AuthHandlers.handleDeleteUser(ss, body),
    'update_user': () => AuthHandlers.handleUpdateUser(ss, body),
    'manage_fleet': () => SystemHandlers.handleManageFleet(ss, body),
    'bulk_manage_fleet': () => SystemHandlers.handleBulkManageFleet(ss, body),
    'update_settings': () => SystemHandlers.handleUpdateSettings(ss, body)
  };
  if (!action || action === 'create' || !routes[action]) return DataHandlers.handleDataSubmission(ss, body);
  return routes[action]();
}`;

const CODE_AUTH = `
const AuthHandlers = {
  handleLogin: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.error("No users found.");
    const data = userSheet.getDataRange().getValues();
    const username = body.username.toLowerCase();
    for (let i = 1; i < data.length; i++) {
        if (data[i][0].toLowerCase() === username && data[i][1] === body.password) {
            return ResponseBuilder.success({ user: { username: data[i][0], name: data[i][2], role: data[i][3] } });
        }
    }
    return ResponseBuilder.error("Invalid credentials.");
  },
  handleRegisterUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users') || ss.insertSheet('Users');
    sheet.appendRow([body.username.toLowerCase(), body.password, body.name, body.role, body.position, new Date().toISOString(), "{}", "TRUE"]);
    return ResponseBuilder.success();
  },
  handleGetUsers: function(ss) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.success({ users: [] });
    const data = sheet.getDataRange().getValues();
    const users = data.slice(1).map(r => ({ username: r[0], name: r[2], role: r[3], position: r[4], isActive: r[7] === "TRUE" }));
    return ResponseBuilder.success({ users });
  },
  handleDeleteUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][0].toLowerCase() === body.username.toLowerCase()) {
        sheet.deleteRow(i + 1);
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("User not found");
  },
  handleUpdateUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][0].toLowerCase() === (body.originalUsername || body.username).toLowerCase()) {
        if (body.username) sheet.getRange(i + 1, 1).setValue(body.username);
        if (body.password) sheet.getRange(i + 1, 2).setValue(body.password);
        if (body.name) sheet.getRange(i + 1, 3).setValue(body.name);
        if (body.role) sheet.getRange(i + 1, 4).setValue(body.role);
        if (body.position) sheet.getRange(i + 1, 5).setValue(body.position);
        if (body.isActive !== undefined) sheet.getRange(i + 1, 8).setValue(body.isActive ? "TRUE" : "FALSE");
        if (body.preferences) sheet.getRange(i + 1, 7).setValue(JSON.stringify(body.preferences));
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("User not found");
  }
};`;

const CODE_CORE_OPS = `
const DataHandlers = {
  handleDataSubmission: function(ss, body) {
    let sheet = ss.getSheetByName(body.sheet) || ss.insertSheet(body.sheet);
    if (sheet.getLastRow() === 0 && body.headers) sheet.appendRow(body.headers);
    sheet.appendRow(body.row);

    // Crucial: Pass reportData to EmailDispatcher
    if (body.reportData) {
      EmailDispatcher.sendInspectionReport(body.reportData);
    }

    return ResponseBuilder.success();
  },
  handleGetRequest: function(ss) {
    const data = {};
    ss.getSheets().forEach(sheet => {
      const name = sheet.getName();
      const lastRow = sheet.getLastRow();
      if (lastRow === 0) { data[name] = []; return; }
      if (name === 'Validation_Data') {
         const values = sheet.getDataRange().getValues();
         const columns = {};
         if (values.length > 0) {
             const headers = values[0];
             headers.forEach((h, idx) => { columns[h] = values.slice(1).map(r => r[idx]).filter(v => v !== ""); });
         }
         data[name] = columns;
      } else { data[name] = sheet.getDataRange().getValues(); }
    });
    return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
  }
};

const EmailDispatcher = {
  sendInspectionReport: function(data) {
    try {
      const settingsSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName('System_Settings');
      let adminEmail = "";
      if (settingsSheet && settingsSheet.getLastRow() > 1) {
        adminEmail = settingsSheet.getRange(2, 3).getValue();
      }

      if (!adminEmail) return;

      const subject = "Official Inspection Report: " + data.truckNo + " (" + (data.safeToLoad === 'Yes' ? 'PASSED' : 'FAILED') + ")";
      const htmlBody = this.buildHtmlReport(data);

      // Use Google's conversion service for PDF attachment
      const blob = Utilities.newBlob(htmlBody, "text/html", "Inspection_Report.html");
      const pdf = blob.getAs("application/pdf").setName("Report_" + data.truckNo + ".pdf");

      MailApp.sendEmail({
        to: adminEmail,
        subject: subject,
        htmlBody: "A new " + data.title + " has been recorded for asset <b>" + data.truckNo + "</b>. The Safe to Load status is: <b>" + (data.safeToLoad || 'N/A') + "</b>. Detailed PDF report is attached.",
        attachments: [pdf]
      });
    } catch (e) {
      Logger.log("Email failed: " + e.toString());
    }
  },

  buildHtmlReport: function(data) {
    // Professional HTML for Email/PDF conversion (No Flexbox, uses Tables for layout compatibility)
    const statusColor = data.safeToLoad === 'Yes' ? '#10b981' : '#ef4444';
    const reportDate = new Date(data.timestamp).toLocaleString();

    return "<html><body style='font-family: sans-serif; padding: 20px; color: #333;'>" +
      "<table width='100%' style='border-bottom: 2px solid #000; padding-bottom: 10px; margin-bottom: 20px;'>" +
        "<tr>" +
          "<td><h1 style='margin: 0; color: #1e3a8a;'>" + data.title.toUpperCase() + "</h1></td>" +
          "<td align='right'><p style='margin: 0; font-size: 12px;'>Date: " + reportDate + "</p></td>" +
        "</tr>" +
      "</table>" +

      "<table width='100%' style='margin-bottom: 20px; font-size: 14px;'>" +
        "<tr>" +
          "<td><b>Asset Reg:</b> " + data.truckNo + "</td>" +
          "<td><b>Trailer/Unit:</b> " + (data.trailerNo || 'N/A') + "</td>" +
        "</tr>" +
        "<tr>" +
          "<td><b>Inspector:</b> " + data.inspectedBy + "</td>" +
          "<td><b>Location:</b> " + data.location + "</td>" +
        "</tr>" +
      "</table>" +

      "<table width='100%' border='1' cellpadding='10' style='border-collapse: collapse; margin-bottom: 20px; border-color: #333;'>" +
        "<tr style='background-color: #f8fafc;'>" +
          "<td width='40%'><b>SAFE TO LOAD STATUS</b></td>" +
          "<td align='center'><span style='font-size: 18px; font-weight: 900; color: " + statusColor + ";'>" + (data.safeToLoad || 'NOT SPECIFIED').toUpperCase() + "</span></td>" +
        "</tr>" +
      "</table>" +

      "<div style='border: 1px solid #ccc; padding: 15px; min-height: 100px; margin-bottom: 20px; font-size: 13px;'>" +
        "<b style='color: #666;'>INSPECTOR REMARKS:</b><br/><br/>" + 
        "<i style='color: #444;'>" + (data.remarks || 'No additional remarks provided.') + "</i>" +
      "</div>" +

      "<table width='100%' style='margin-top: 50px; font-size: 10px; color: #888;'>" +
        "<tr>" +
          "<td align='center' style='border-top: 1px solid #ddd; padding-top: 5px; width: 45%;'>Inspector Acknowledged</td>" +
          "<td width='10%'></td>" +
          "<td align='center' style='border-top: 1px solid #ddd; padding-top: 5px; width: 45%;'>Driver Acknowledged</td>" +
        "</tr>" +
      "</table>" +

      "<p style='font-size: 9px; color: #aaa; text-align: center; margin-top: 30px;'>System Generated by " + data.companyName + " SafetyCheck Pro Hub</p>" +
      "</body></html>";
  }
};

const SystemHandlers = {
  handleManageFleet: function(ss, body) {
    let sheet = ss.getSheetByName('Validation_Data') || ss.insertSheet('Validation_Data');
    if (sheet.getLastRow() === 0) {
      sheet.appendRow(["Driver_Name","Inspector_Name","Location","Position","Misc1","Misc2","Misc3","Truck_Reg_No","Trailer_Reg_No"]);
      sheet.setFrozenRows(1);
    }
    const colIdx = body.type === 'truck' ? 8 : 9; 
    sheet.getRange(sheet.getLastRow() + 1, colIdx).setValue(body.value);
    return ResponseBuilder.success();
  },
  handleBulkManageFleet: function(ss, body) {
    let sheet = ss.getSheetByName('Validation_Data') || ss.insertSheet('Validation_Data');
    const trucks = (body.trucks || []).map(t => [t]);
    const trailers = (body.trailers || []).map(t => [t]);
    if (trucks.length > 0) sheet.getRange(sheet.getLastRow() + 1, 8, trucks.length, 1).setValues(trucks);
    if (trailers.length > 0) sheet.getRange(sheet.getLastRow() + 1, 9, trailers.length, 1).setValues(trailers);
    return ResponseBuilder.success();
  },
  handleUpdateSettings: function(ss, body) {
    let sheet = ss.getSheetByName('System_Settings') || ss.insertSheet('System_Settings');
    const row = ["SYS-CONFIG-001", body.companyName, body.managerEmail, new Date(), "Admin", body.companyLogo || "", body.mobileApkLink || "", body.webAppUrl || "", body.maintenanceMode ? "TRUE" : "FALSE", body.maintenanceMessage || ""];
    if (sheet.getLastRow() < 2) sheet.appendRow(["ID","ORG_NAME","ADMIN_EMAIL","UPDATED_AT","UPDATED_BY","LOGO","APK_URL","WEB_URL","MAINT_MODE","MAINT_MSG"]);
    sheet.getRange(2, 1, 1, row.length).setValues([row]);
    return ResponseBuilder.success();
  }
};`;

const CODE_LIB = `const ResponseBuilder = {
  success: function(data = {}) { return this.build({ status: "success", ...data }); },
  error: function(message) { return this.build({ status: "error", message: message }); },
  build: function(data) { return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON); }
};`;

export const BACKEND_FILES: Record<string, string> = {
    '1_Controller.gs': CODE_CONTROLLER,
    '2_Auth.gs': CODE_AUTH,
    '3_Core.gs': CODE_CORE_OPS,
    '5_Utils.gs': CODE_LIB
};

export const BACKEND_SCRIPT_TEMPLATE = Object.values(BACKEND_FILES).join('\n\n');

