// 3. CORE OPERATIONS (Data, Systems, Subscription)


const DataHandlers = {
  handleDataSubmission: function(ss, body) {
    const sheetName = body.sheet;
    const headers = body.headers;
    const rowData = body.row;
    let sheet = ss.getSheetByName(sheetName);
    if (!sheet) {
      sheet = ss.insertSheet(sheetName);
      if (headers && Array.isArray(headers)) {
        sheet.appendRow(headers);
        sheet.getRange(1, 1, 1, headers.length).setFontWeight("bold");
        sheet.setFrozenRows(1);
      }
    }
    if (sheet.getLastRow() === 0 && body.headers) {
      sheet.appendRow(body.headers);
      sheet.setFrozenRows(1);
    }
    const safeRow = rowData.map(r => (r === null || r === undefined) ? "" : String(r));
    sheet.appendRow(safeRow);

    // TRACKING RESTORATION: Mark request as completed if requestId is provided
    if (body.requestId) {
        const reqSheet = ss.getSheetByName('Inspection_Requests');
        if (reqSheet) {
            const reqData = reqSheet.getDataRange().getValues();
            for (let i = 1; i < reqData.length; i++) {
                if (String(reqData[i][0]) === String(body.requestId)) {
                    reqSheet.getRange(i + 1, 10).setValue('Completed'); // Column J
                    break;
                }
            }
        }
    }

    const skipValidation = ['System_Settings', 'Validation_Data', 'Users', 'Acknowledgements', 'SystemNotification', 'Subscription_Data', 'Support_Tickets', 'Inspection_Requests'];
    if (!skipValidation.includes(sheetName)) {
       Validation.updateFromRow(ss, body);
       try { 
          EmailHandlers.sendEmailNotifications(ss, body, sheetName); 
       } catch (e) { 
          Logger.log(ss, "EMAIL_FAILURE", "CRITICAL: " + e.toString()); 
       }
    }

    // Crucial: Pass reportData to EmailDispatcher
    if (body.reportData) {
      EmailDispatcher.sendInspectionReport(body.reportData);
    }

    return ResponseBuilder.success({ sheet: sheetName });
  },

  handleGetRequest: function(ss) {
    const sheets = ss.getSheets();
    const data = {};
    sheets.forEach(sheet => {
      const name = sheet.getName();
      if (name === 'Users' || name === 'System_Logs') return;

      const lastRow = sheet.getLastRow();
      if (lastRow === 0) {
          data[name] = [];
          return;
      }

      if (name === 'Validation_Data') {
         if (lastRow > 1) {
            const range = sheet.getRange(2, 1, lastRow - 1, sheet.getLastColumn());
            const values = range.getValues();
            const columns = {};
            const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
            headers.forEach((h, colIndex) => {
               columns[h] = [...new Set(values.map(row => row[colIndex]).filter(c => c !== ""))]; 
            });
            data[name] = columns;
         } else { data[name] = {}; }
      } else if (name === 'Acknowledgements') {
          data[name] = lastRow > 1 ? sheet.getRange(2, 1, lastRow - 1, 1).getValues().flat() : [];
      } else if (name === 'System_Settings') {
          data[name] = lastRow > 0 ? sheet.getRange(1, 1, lastRow, sheet.getLastColumn()).getValues() : [];
      } else if (name === 'Subscription_Data') {
          const values = sheet.getDataRange().getValues();
          if (values.length > 1) {
            const history = [];
            // IMPROVED: Filter out truly empty rows (where date is missing) - from update code
            for (let i = 1; i < values.length; i++) {
                const row = values[i];
                if (!row[2]) continue; // Skip if Date column is empty

                let expiry = row[2];
                if (expiry instanceof Date) {
                  expiry = Utilities.formatDate(expiry, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
                } else {
                  expiry = String(expiry).trim();
                  if (expiry === "" || expiry === "null") continue;
                }

                let ts = row[4];
                if (ts instanceof Date) ts = Utilities.formatDate(ts, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
                else if (typeof ts === 'string') ts = ts.split('T')[0];

                history.push({
                    status: row[0] || "Expired",
                    plan: row[1] || "None",
                    expiryDate: expiry,
                    processedBy: row[3] || 'System',
                    timestamp: ts || ''
                });
            }

            // If no valid entries found after filtering, return EXPIRED
            const last = history.length > 0 ? history[history.length - 1] : { status: "Expired", plan: "None", expiryDate: "" };
            data[name] = { current: last, history: history };
          } else { data[name] = { current: { status: "Expired", plan: "None", expiryDate: "" }, history: [] }; }
      } else {
         const startRow = Math.max(1, lastRow - 150);
         const values = sheet.getRange(startRow, 1, lastRow - startRow + 1, sheet.getLastColumn()).getValues();
         if (startRow > 1) values.unshift(sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0]);
         data[name] = values;
      }
    });
    return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
  }
};

const EmailDispatcher = {
  sendInspectionReport: function(data) {
    try {
      const settingsSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName('System_Settings');
      let adminEmail = "";
      if (settingsSheet && settingsSheet.getLastRow() > 1) {
        adminEmail = settingsSheet.getRange(2, 3).getValue();
      }

      if (!adminEmail) return;

      const subject = "Official Inspection Report: " + data.truckNo + " (" + (data.safeToLoad === 'Yes' ? 'PASSED' : 'FAILED') + ")";
      const htmlBody = this.buildHtmlReport(data);

      // Use Google's conversion service for PDF attachment
      const blob = Utilities.newBlob(htmlBody, "text/html", "Inspection_Report.html");
      const pdf = blob.getAs("application/pdf").setName("Report_" + data.truckNo + ".pdf");

      MailApp.sendEmail({
        to: adminEmail,
        subject: subject,
        htmlBody: "A new " + data.title + " has been recorded for asset <b>" + data.truckNo + "</b>. The Safe to Load status is: <b>" + (data.safeToLoad || 'N/A') + "</b>. Detailed PDF report is attached.",
        attachments: [pdf]
      });
    } catch (e) {
      Logger.log("Email failed: " + e.toString());
    }
  },

  buildHtmlReport: function(data) {
    // Professional HTML for Email/PDF conversion (No Flexbox, uses Tables for layout compatibility)
    const statusColor = data.safeToLoad === 'Yes' ? '#10b981' : '#ef4444';
    const reportDate = new Date(data.timestamp).toLocaleString();

    return "<html><body style='font-family: sans-serif; padding: 20px; color: #333;'>" +
      "<table width='100%' style='border-bottom: 2px solid #000; padding-bottom: 10px; margin-bottom: 20px;'>" +
        "<tr>" +
          "<td><h1 style='margin: 0; color: #1e3a8a;'>" + data.title.toUpperCase() + "</h1></td>" +
          "<td align='right'><p style='margin: 0; font-size: 12px;'>Date: " + reportDate + "</p></td>" +
        "</tr>" +
      "</table>" +

      "<table width='100%' style='margin-bottom: 20px; font-size: 14px;'>" +
        "<tr>" +
          "<td><b>Asset Reg:</b> " + data.truckNo + "</td>" +
          "<td><b>Trailer/Unit:</b> " + (data.trailerNo || 'N/A') + "</td>" +
        "</tr>" +
        "<tr>" +
          "<td><b>Inspector:</b> " + data.inspectedBy + "</td>" +
          "<td><b>Location:</b> " + data.location + "</td>" +
        "</tr>" +
      "</table>" +

      "<table width='100%' border='1' cellpadding='10' style='border-collapse: collapse; margin-bottom: 20px; border-color: #333;'>" +
        "<tr style='background-color: #f8fafc;'>" +
          "<td width='40%'><b>SAFE TO LOAD STATUS</b></td>" +
          "<td align='center'><span style='font-size: 18px; font-weight: 900; color: " + statusColor + ";'>" + (data.safeToLoad || 'NOT SPECIFIED').toUpperCase() + "</span></td>" +
        "</tr>" +
      "</table>" +

      "<div style='border: 1px solid #ccc; padding: 15px; min-height: 100px; margin-bottom: 20px; font-size: 13px;'>" +
        "<b style='color: #666;'>INSPECTOR REMARKS:</b><br/><br/>" + 
        "<i style='color: #444;'>" + (data.remarks || 'No additional remarks provided.') + "</i>" +
      "</div>" +

      "<table width='100%' style='margin-top: 50px; font-size: 10px; color: #888;'>" +
        "<tr>" +
          "<td align='center' style='border-top: 1px solid #ddd; padding-top: 5px; width: 45%;'>Inspector Acknowledged</td>" +
          "<td width='10%'></td>" +
          "<td align='center' style='border-top: 1px solid #ddd; padding-top: 5px; width: 45%;'>Driver Acknowledged</td>" +
        "</tr>" +
      "</table>" +

      "<p style='font-size: 9px; color: #aaa; text-align: center; margin-top: 30px;'>System Generated by " + data.companyName + " SafetyCheck Pro Hub</p>" +
      "</body></html>";
  }
};

const SystemHandlers = {
  // AUTO-CLEANUP: Deletes notifications older than 24 hours
  cleanupOldNotifications: function(ss) {
    const sheetsToClean = ['SystemNotification', 'Acknowledgements'];
    const now = new Date().getTime();
    const oneDay = 24 * 60 * 60 * 1000;

    sheetsToClean.forEach(name => {
        const sheet = ss.getSheetByName(name);
        if (!sheet) return;
        const data = sheet.getDataRange().getValues();
        if (data.length <= 1) return;
        const tsColIdx = (name === 'SystemNotification') ? 4 : 3;
        for (let i = data.length - 1; i >= 1; i--) {
            const tsValue = data[i][tsColIdx];
            if (!tsValue) continue;
            const ts = new Date(tsValue).getTime();
            if (now - ts > oneDay) {
                sheet.deleteRow(i + 1);
            }
        }
    });
  },

  handleBroadcast: function(ss, body) {
    let notifSheet = ss.getSheetByName('SystemNotification');
    if (!notifSheet) {
        notifSheet = ss.insertSheet('SystemNotification');
        notifSheet.appendRow(["Notification_ID", "Recipient", "Type", "Message", "Timestamp", "IsRead", "ActionLink"]);
        notifSheet.setFrozenRows(1);
    }
    if (notifSheet.getLastRow() === 0) {
        notifSheet.appendRow(["Notification_ID", "Recipient", "Type", "Message", "Timestamp", "IsRead", "ActionLink"]);
        notifSheet.setFrozenRows(1);
    }
    const notifId = "SYS-BCAST-" + Date.now();
    notifSheet.appendRow([
        notifId, 
        "All", 
        body.type || "info", 
        body.message, 
        new Date().toISOString(), 
        "FALSE", 
        body.actionLink || ""
    ]);
    return ResponseBuilder.success({ message: "Broadcast sent", id: notifId });
  },

  handleRequestInspection: function(ss, body) {
    let reqSheet = ss.getSheetByName('Inspection_Requests');
    if (!reqSheet) {
        reqSheet = ss.insertSheet('Inspection_Requests');
        reqSheet.appendRow(['Request_ID', 'Requester', 'Role', 'Truck_No', 'Trailer_No', 'Type', 'Reason', 'Priority', 'Assigned_Inspector', 'Status', 'Timestamp']);
        reqSheet.setFrozenRows(1);
    }
    const reqId = "REQ-" + Date.now();
    reqSheet.appendRow([
        reqId, body.requester, body.role, body.truckNo, body.trailerNo, body.type, body.reason, body.priority,
        body.assignedInspector || 'Unassigned', 'Pending', new Date().toISOString()
    ]);

    // Broadcast to relevant staff
    const msg = "New Inspection Requested: Truck " + body.truckNo + " (" + (body.priority || 'Normal') + ")";
    const actionLink = "request:start_inspection|" + body.type + "|" + body.truckNo + "|" + (body.trailerNo || '') + "|" + body.requester + "|" + (body.reason || '');

    SystemHandlers.handleBroadcast(ss, {
        type: (body.priority === 'Urgent' || body.priority === 'Safety Concern') ? 'critical' : 'info',
        message: msg,
        recipient: 'inspector',
        action: reqId + "-" + actionLink
    });

    return ResponseBuilder.success({ requestId: reqId });
  },

  handleAcknowledgeIssue: function(ss, body) {
    let ackSheet = ss.getSheetByName('Acknowledgements');
    if (!ackSheet) {
        ackSheet = ss.insertSheet('Acknowledgements');
        ackSheet.appendRow(['Issue_ID', 'Acknowledged_By', 'Role', 'Timestamp']);
        ackSheet.setFrozenRows(1);
    }
    if (ackSheet.getLastRow() === 0) {
        ackSheet.appendRow(['Issue_ID', 'Acknowledged_By', 'Role', 'Timestamp']);
        ackSheet.setFrozenRows(1);
    }
    const issueId = String(body.issueId);
    const data = ackSheet.getDataRange().getValues();
    if (!data.some(row => String(row[0]) === issueId)) {
         ackSheet.appendRow([issueId, body.user || 'Unknown', body.role || 'Unknown', new Date().toISOString()]);
    }
    return ResponseBuilder.success({ message: "Issue acknowledged." });
  },

  handleGetAcknowledgements: function(ss) {
    let ackSheet = ss.getSheetByName('Acknowledgements');
    if (!ackSheet) return ResponseBuilder.success({ ids: [] });
    const data = ackSheet.getDataRange().getValues();
    const ids = [];
    for (let i = 1; i < data.length; i++) if (data[i][0]) ids.push(String(data[i][0]));
    return ResponseBuilder.success({ ids: ids });
  },

  handleMarkNotificationRead: function(ss, body) {
    const sheet = ss.getSheetByName('SystemNotification');
    if (!sheet) return ResponseBuilder.error("Notification sheet not found");
    const idToMark = String(body.id);
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
        if (String(data[i][0]) === idToMark) {
            sheet.getRange(i + 1, 6).setValue("TRUE");
            return ResponseBuilder.success({ message: "Marked as read" });
        }
    }
    return ResponseBuilder.error("ID not found");
  },

  handleManageFleet: function(ss, body) {
    let sheet = ss.getSheetByName('Validation_Data') || ss.insertSheet('Validation_Data');
    const lastRow = sheet.getLastRow();
    // Ensure standard headers exist
    if (lastRow === 0) {
      sheet.appendRow(["Driver_Name","Inspector_Name","Location","Position","Misc1","Misc2","Misc3","Truck_Reg_No","Trailer_Reg_No"]);
      sheet.setFrozenRows(1);
    }

    const colIdx = body.type === 'truck' ? 8 : 9; // Col H is 8, Col I is 9
    const range = sheet.getRange(1, colIdx, Math.max(1, sheet.getLastRow()), 1);
    const colValues = range.getValues().flat();
    const firstEmpty = colValues.indexOf("");
    const targetRow = firstEmpty === -1 ? sheet.getLastRow() + 1 : firstEmpty + 1;

    sheet.getRange(targetRow, colIdx).setValue(body.value);
    return ResponseBuilder.success({ message: "Asset added to Col " + (colIdx === 8 ? "H" : "I") });
  },

  handleBulkManageFleet: function(ss, body) {
    let sheet = ss.getSheetByName('Validation_Data') || ss.insertSheet('Validation_Data');
    const lastRow = sheet.getLastRow();
    if (lastRow === 0) {
      sheet.appendRow(["Driver_Name","Inspector_Name","Location","Position","Misc1","Misc2","Misc3","Truck_Reg_No","Trailer_Reg_No"]);
      sheet.setFrozenRows(1);
    }

    const trucks = body.trucks || [];
    const trailers = body.trailers || [];

    const getFirstEmptyInCol = (col) => {
        const vals = sheet.getRange(1, col, Math.max(1, sheet.getLastRow()), 1).getValues().flat();
        const idx = vals.indexOf("");
        return idx === -1 ? sheet.getLastRow() + 1 : idx + 1;
    };

    if (trucks.length > 0) {
        const startRow = getFirstEmptyInCol(8);
        sheet.getRange(startRow, 8, trucks.length, 1).setValues(trucks.map(t => [t]));
    }

    if (trailers.length > 0) {
        const startRow = getFirstEmptyInCol(9);
        sheet.getRange(startRow, 9, trailers.length, 1).setValues(trailers.map(t => [t]));
    }

    return ResponseBuilder.success({ message: "Bulk import complete" });
  },

  handleUpdateSettings: function(ss, body) {
    // Keeping both implementations - original appends new row, update overwrites row 2
    let settingsSheet = ss.getSheetByName('System_Settings');
    if (!settingsSheet) {
        settingsSheet = ss.insertSheet('System_Settings');
        settingsSheet.appendRow(["CompanyName", "ManagerEmail", "UpdatedBy", "Timestamp", "LogoBase64", "MobileApkLink", "WebAppUrl", "MaintenanceMode", "MaintenanceMessage"]);
        settingsSheet.setFrozenRows(1);
    }

    // Add update functionality (overwrites row 2)
    const updateRow = [body.companyName || '', body.managerEmail || '', new Date(), body.updatedBy || "Admin", body.companyLogo || '', "", "", body.maintenanceMode ? "TRUE" : "FALSE", body.maintenanceMessage || ''];

    // If sheet has less than 2 rows, create the header and append
    if (settingsSheet.getLastRow() < 2) {
      if (settingsSheet.getLastRow() === 0) {
        settingsSheet.appendRow(["CompanyName", "ManagerEmail", "UpdatedBy", "Timestamp", "LogoBase64", "MobileApkLink", "WebAppUrl", "MaintenanceMode", "MaintenanceMessage"]);
      }
      settingsSheet.appendRow(updateRow);
    } else {
      // Overwrite row 2 with new settings
      settingsSheet.getRange(2, 1, 1, updateRow.length).setValues([updateRow]);
    }

    return ResponseBuilder.success({ message: "Settings updated" });
  }
};

const SubscriptionHandlers = {
  handleCheckSubscription: function(ss) {
    let subSheet = ss.getSheetByName('Subscription_Data');
    if (!subSheet) {
        subSheet = ss.insertSheet('Subscription_Data');
        subSheet.appendRow(["Status", "Plan", "Expiry_Date", "Last_Updated"]);
        subSheet.setFrozenRows(1);
    }
    if (subSheet.getLastRow() < 2) {
        const defaultExpiry = new Date();
        defaultExpiry.setDate(defaultExpiry.getDate() + 30);
        subSheet.appendRow(["Active", "Trial", defaultExpiry.toISOString(), new Date().toISOString()]);
    }
    const lastRow = subSheet.getLastRow();
    const data = subSheet.getRange(lastRow, 1, 1, 4).getValues()[0];
    let status = data[0];
    const expiry = new Date(data[2]);
    const now = new Date();
    if (status === 'Active' && !isNaN(expiry.getTime()) && now > expiry) {
        status = 'Expired';
        subSheet.getRange(lastRow, 1).setValue('Expired');
    }
    return ResponseBuilder.success({ 
        subscription: {
            status: status,
            plan: data[1],
            expiryDate: data[2],
            daysRemaining: Math.ceil((expiry.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))
        }
    });
  },

  handleExtendSubscription: function(ss, body) {
    let subSheet = ss.getSheetByName('Subscription_Data');
    if (!subSheet) {
        subSheet = ss.insertSheet('Subscription_Data');
        subSheet.appendRow(["Status", "Plan", "Expiry_Date", "Last_Updated"]);
        subSheet.setFrozenRows(1);
    }
    // Robust header check: Check if A1 is empty
    if (subSheet.getLastRow() === 0 || subSheet.getRange(1,1).getValue() === "") {
      subSheet.getRange(1, 1, 1, 5).setValues([["Status", "Plan", "ExpiryDate", "ProcessedBy", "Timestamp"]]);
      subSheet.setFrozenRows(1);
    }

    // SUPPORT DYNAMIC PLAN SELECTION - use either days parameter or direct expiry date
    if (body.days) {
      const daysToAdd = parseInt(body.days || 30);
      const lastRow = subSheet.getLastRow();
      const currentData = subSheet.getRange(lastRow, 1, 1, 4).getValues()[0];
      let currentExpiry = new Date(currentData[2]);
      const now = new Date();
      if (!currentData[2] || isNaN(currentExpiry.getTime()) || currentExpiry < now) currentExpiry = now;
      currentExpiry.setDate(currentExpiry.getDate() + daysToAdd);

      subSheet.appendRow(["Active", body.plan || "Enterprise", currentExpiry.toISOString(), body.processedBy || "Admin", new Date().toISOString()]);
    } else if (body.expiryDate) {
      // Direct expiry date provided
      subSheet.appendRow(["Active", body.plan || "Enterprise", body.expiryDate, body.processedBy || "Admin", new Date().toISOString()]);
    } else {
      return ResponseBuilder.error("Either 'days' or 'expiryDate' must be provided");
    }

    return ResponseBuilder.success({ message: "Subscription extended successfully" });
  }
};

