        "<tr style='background-color: #f8fafc;'>" +
          "<td width='40%'><b>SAFE TO LOAD STATUS</b></td>" +
          "<td align='center'><span style='font-size: 18px; font-weight: 900; color: " + statusColor + ";'>" + (data.safeToLoad || 'NOT SPECIFIED').toUpperCase() + "</span></td>" +
        "</tr>" +
      "</table>" +

      "<div style='border: 1px solid #ccc; padding: 15px; min-height: 100px; margin-bottom: 20px; font-size: 13px;'>" +
        "<b style='color: #666;'>INSPECTOR REMARKS:</b><br/><br/>" + 
        "<i style='color: #444;'>" + (data.remarks || 'No additional remarks provided.') + "</i>" +
      "</div>" +

      "<table width='100%' style='margin-top: 50px; font-size: 10px; color: #888;'>" +
        "<tr>" +
          "<td align='center' style='border-top: 1px solid #ddd; padding-top: 5px; width: 45%;'>Inspector Acknowledged</td>" +
          "<td width='10%'></td>" +
          "<td align='center' style='border-top: 1px solid #ddd; padding-top: 5px; width: 45%;'>Driver Acknowledged</td>" +
        "</tr>" +
      "</table>" +

      "<p style='font-size: 9px; color: #aaa; text-align: center; margin-top: 30px;'>System Generated by " + data.companyName + " SafetyCheck Pro Hub</p>" +
      "</body></html>";
  }
};

const SystemHandlers = {
  cleanupOldNotifications: function(ss) {
    const sheetsToClean = ['SystemNotification', 'Acknowledgements'];
    const now = new Date().getTime();
    const oneDay = 24 * 60 * 60 * 1000;

    sheetsToClean.forEach(name => {
        const sheet = ss.getSheetByName(name);
        if (!sheet) return;
        const data = sheet.getDataRange().getValues();
        if (data.length <= 1) return;
        const tsColIdx = (name === 'SystemNotification') ? 4 : 3;
        for (let i = data.length - 1; i >= 1; i--) {
            const tsValue = data[i][tsColIdx];
            if (!tsValue) continue;
            const ts = new Date(tsValue).getTime();
            if (now - ts > oneDay) {
                sheet.deleteRow(i + 1);
            }
        }
    });
  },

  handleBroadcast: function(ss, body) {
    let notifSheet = ss.getSheetByName('SystemNotification');
    if (!notifSheet) {
        notifSheet = ss.insertSheet('SystemNotification');
        notifSheet.appendRow(["Notification_ID", "Recipient", "Type", "Message", "Timestamp", "IsRead", "ActionLink"]);
        notifSheet.setFrozenRows(1);
    }
    const notifId = "SYS-BCAST-" + Date.now();
    notifSheet.appendRow([notifId, "All", body.type || "info", body.message, new Date().toISOString(), "FALSE", body.actionLink || ""]);
    return ResponseBuilder.success({ message: "Broadcast sent", id: notifId });
  },

  handleRequestInspection: function(ss, body) {
    let reqSheet = ss.getSheetByName('Inspection_Requests');
    if (!reqSheet) {
        reqSheet = ss.insertSheet('Inspection_Requests');
        reqSheet.appendRow(['Request_ID', 'Requester', 'Role', 'Truck_No', 'Trailer_No', 'Type', 'Reason', 'Priority', 'Assigned_Inspector', 'Status', 'Timestamp']);
        reqSheet.setFrozenRows(1);
    }
    const reqId = "REQ-" + Date.now();
    reqSheet.appendRow([reqId, body.requester, body.role, body.truckNo, body.trailerNo, body.type, body.reason, body.priority, body.assignedInspector || 'Unassigned', 'Pending', new Date().toISOString()]);

    const msg = "New Inspection Requested: Truck " + body.truckNo + " (" + (body.priority || 'Normal') + ")";
    const actionLink = "request:start_inspection|" + body.type + "|" + body.truckNo + "|" + (body.trailerNo || '') + "|" + body.requester + "|" + (body.reason || '');

    SystemHandlers.handleBroadcast(ss, {
        type: (body.priority === 'Urgent' || body.priority === 'Safety Concern') ? 'critical' : 'info',
        message: msg,
        recipient: 'inspector',
        action: reqId + "-" + actionLink
    });

    return ResponseBuilder.success({ requestId: reqId });
  },

  handleAcknowledgeIssue: function(ss, body) {
    let ackSheet = ss.getSheetByName('Acknowledgements');
    if (!ackSheet) {
        ackSheet = ss.insertSheet('Acknowledgements');
        ackSheet.appendRow(['Issue_ID', 'Acknowledged_By', 'Role', 'Timestamp']);
        ackSheet.setFrozenRows(1);
    }
    const issueId = String(body.issueId);
    const data = ackSheet.getDataRange().getValues();
    if (!data.some(row => String(row[0]) === issueId)) {
         ackSheet.appendRow([issueId, body.user || 'Unknown', body.role || 'Unknown', new Date().toISOString()]);
    }
    return ResponseBuilder.success({ message: "Issue acknowledged." });
  },

  handleMarkNotificationRead: function(ss, body) {
    const sheet = ss.getSheetByName('SystemNotification');
    if (!sheet) return ResponseBuilder.error("Notification sheet not found");
    const idToMark = String(body.id);
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
        if (String(data[i][0]) === idToMark) {
            sheet.getRange(i + 1, 6).setValue("TRUE");
            return ResponseBuilder.success({ message: "Marked as read" });
        }
    }
    return ResponseBuilder.error("ID not found");
  },

  handleManageFleet: function(ss, body) {
    let sheet = ss.getSheetByName('Validation_Data') || ss.insertSheet('Validation_Data');
    if (sheet.getLastRow() === 0) {
      sheet.appendRow(["Driver_Name","Inspector_Name","Location","Position","Misc1","Misc2","Misc3","Truck_Reg_No","Trailer_Reg_No"]);
      sheet.setFrozenRows(1);
    }
    const colIdx = body.type === 'truck' ? 8 : 9; 
    const range = sheet.getRange(1, colIdx, Math.max(1, sheet.getLastRow()), 1);
    const colValues = range.getValues().flat();
    const firstEmpty = colValues.indexOf("");
    const targetRow = firstEmpty === -1 ? sheet.getLastRow() + 1 : firstEmpty + 1;
    sheet.getRange(targetRow, colIdx).setValue(body.value);
    return ResponseBuilder.success({ message: "Asset added" });
  },

  handleBulkManageFleet: function(ss, body) {
    let sheet = ss.getSheetByName('Validation_Data') || ss.insertSheet('Validation_Data');
    if (sheet.getLastRow() === 0) {
      sheet.appendRow(["Driver_Name","Inspector_Name","Location","Position","Misc1","Misc2","Misc3","Truck_Reg_No","Trailer_Reg_No"]);
      sheet.setFrozenRows(1);
    }
    const trucks = body.trucks || [];
    const trailers = body.trailers || [];
    const getFirstEmptyInCol = (col) => {
        const vals = sheet.getRange(1, col, Math.max(1, sheet.getLastRow()), 1).getValues().flat();
        const idx = vals.indexOf("");
        return idx === -1 ? sheet.getLastRow() + 1 : idx + 1;
    };
    if (trucks.length > 0) sheet.getRange(getFirstEmptyInCol(8), 8, trucks.length, 1).setValues(trucks.map(t => [t]));
    if (trailers.length > 0) sheet.getRange(getFirstEmptyInCol(9), 9, trailers.length, 1).setValues(trailers.map(t => [t]));
    return ResponseBuilder.success({ message: "Bulk import complete" });
  },

  handleUpdateSettings: function(ss, body) {
    let settingsSheet = ss.getSheetByName('System_Settings') || ss.insertSheet('System_Settings');
    const updateRow = [body.companyName || '', body.managerEmail || '', new Date(), body.updatedBy || "Admin", body.companyLogo || '', "", "", body.maintenanceMode ? "TRUE" : "FALSE", body.maintenanceMessage || ''];
    if (settingsSheet.getLastRow() < 2) {
      if (settingsSheet.getLastRow() === 0) settingsSheet.appendRow(["CompanyName", "ManagerEmail", "UpdatedBy", "Timestamp", "LogoBase64", "MobileApkLink", "WebAppUrl", "MaintenanceMode", "MaintenanceMessage"]);
      settingsSheet.appendRow(updateRow);
    } else {
      settingsSheet.getRange(2, 1, 1, updateRow.length).setValues([updateRow]);
    }
    return ResponseBuilder.success({ message: "Settings updated" });
  }
};

const SubscriptionHandlers = {
  handleCheckSubscription: function(ss) {
    let subSheet = ss.getSheetByName('Subscription_Data') || ss.insertSheet('Subscription_Data');
    if (subSheet.getLastRow() < 2) {
        const defaultExpiry = new Date();
        defaultExpiry.setDate(defaultExpiry.getDate() + 30);
        subSheet.appendRow(["Active", "Trial", defaultExpiry.toISOString(), new Date().toISOString()]);
    }
    const lastRow = subSheet.getLastRow();
    const data = subSheet.getRange(lastRow, 1, 1, 4).getValues()[0];
    let status = data[0];
    const expiry = new Date(data[2]);
    const now = new Date();
    if (status === 'Active' && !isNaN(expiry.getTime()) && now > expiry) {
        status = 'Expired';
        subSheet.getRange(lastRow, 1).setValue('Expired');
    }
    return ResponseBuilder.success({ 
        subscription: {
            status: status, plan: data[1], expiryDate: data[2],
            daysRemaining: Math.ceil((expiry.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))
        }
    });
  },

  handleExtendSubscription: function(ss, body) {
    let subSheet = ss.getSheetByName('Subscription_Data') || ss.insertSheet('Subscription_Data');
    if (subSheet.getLastRow() === 0) {
      subSheet.getRange(1, 1, 1, 5).setValues([["Status", "Plan", "ExpiryDate", "ProcessedBy", "Timestamp"]]);
      subSheet.setFrozenRows(1);
    }
    if (body.days) {
      const daysToAdd = parseInt(body.days || 30);
      const lastRow = subSheet.getLastRow();
      const currentData = subSheet.getRange(lastRow, 1, 1, 3).getValues()[0];
      let currentExpiry = new Date(currentData[2]);
      const now = new Date();
      if (!currentData[2] || isNaN(currentExpiry.getTime()) || currentExpiry < now) currentExpiry = now;
      currentExpiry.setDate(currentExpiry.getDate() + daysToAdd);
      subSheet.appendRow(["Active", body.plan || "Enterprise", currentExpiry.toISOString(), body.processedBy || "Admin", new Date().toISOString()]);
    } else if (body.expiryDate) {
      subSheet.appendRow(["Active", body.plan || "Enterprise", body.expiryDate, body.processedBy || "Admin", new Date().toISOString()]);
    } else {
      return ResponseBuilder.error("Missing parameters");
    }
    return ResponseBuilder.success({ message: "Subscription updated" });
  }
};
`;

const CODE_LIB = `const ResponseBuilder = {
  success: function(data = {}) { return this.build({ status: "success", ...data }); },
  error: function(message) { return this.build({ status: "error", message: message }); },
  build: function(data) { return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON); }
};`;

export const BACKEND_FILES: Record<string, string> = {
    '1_Controller.gs': CODE_CONTROLLER,
    '2_Auth.gs': CODE_AUTH,
    '3_Core.gs': CODE_CORE_OPS,
    '5_Utils.gs': CODE_LIB
};

export const BACKEND_SCRIPT_TEMPLATE = Object.values(BACKEND_FILES).join('\n\n');

